import { createTheme } from '@mui/material/styles';

const theme = createTheme({
  palette: {
    mode: 'dark',
    primary: {
      main: '#6cc7ff',
    },
    secondary: {
      main: '#8dffdc',
    },
    error: {
      main: '#ff6b7a',
    },
    text: {
      primary: '#ecf7ff',
      secondary: '#bfd6e5',
    },
    background: {
      default: '#091728',
      paper: 'rgba(255,255,255,0.14)',
    },
  },
  typography: {
    fontFamily: '"Avenir Next", "Segoe UI", "Trebuchet MS", sans-serif',
    h4: {
      letterSpacing: 0.2,
    },
    h6: {
      letterSpacing: 0.2,
    },
  },
  shape: {
    borderRadius: 14,
  },
  components: {
    MuiCssBaseline: {
      styleOverrides: {
        body: {
          backgroundColor: '#091728',
        },
      },
    },
    MuiPaper: {
      styleOverrides: {
        root: {
          border: '1px solid rgba(255,255,255,0.28)',
          backdropFilter: 'blur(14px)',
          WebkitBackdropFilter: 'blur(14px)',
        },
      },
    },
    MuiCard: {
      styleOverrides: {
        root: {
          boxShadow: '0 18px 40px rgba(2, 8, 20, 0.35)',
          border: '1px solid rgba(255,255,255,0.28)',
        },
      },
    },
    MuiTextField: {
      styleOverrides: {
        root: {
          '& .MuiOutlinedInput-root': {
            background: 'rgba(7, 24, 42, 0.42)',
          },
        },
      },
    },
    MuiDialog: {
      styleOverrides: {
        paper: {
          background: 'linear-gradient(130deg, rgba(19, 47, 76, 0.86), rgba(14, 30, 48, 0.84))',
          border: '1px solid rgba(255,255,255,0.2)',
        },
      },
    },
  },
});

export default theme;
